import React from "react";
import { Link } from "react-router-dom";

export default function Footer() {
  return (
    <footer style={{
      background: "var(--surface)",
      borderTop: "1px solid var(--border)",
      padding: "3.5rem 0 2rem",
    }}>
      <div className="container-lg">
        <div className="row align-items-center gy-3">
          <div className="col-md-4">
            <div style={{ fontFamily: "var(--font-display)", fontWeight: 900, fontSize: "1.8rem" }}>
              JY<span style={{ color: "var(--accent)" }}>.</span>
            </div>
            <p style={{ color: "var(--text-muted)", fontSize: "0.82rem", marginTop: "0.4rem" }}>
              Software Developer · Nagercoil, TN
            </p>
          </div>
          <div className="col-md-4 text-md-center">
            <div className="d-flex justify-content-md-center gap-4">
              {[
                { href: "mailto:jerisha.y26@gmail.com", icon: "bi-envelope-fill", label: "Email" },
                { href: "tel:+919345830402", icon: "bi-telephone-fill", label: "Phone" },
                { href: "https://github.com", icon: "bi-github", label: "GitHub" },
                { href: "https://linkedin.com", icon: "bi-linkedin", label: "LinkedIn" },
              ].map((s) => (
                <a key={s.icon} href={s.href} title={s.label}
                  style={{ color: "var(--text-muted)", fontSize: "1.15rem", transition: "color 0.2s" }}
                  onMouseEnter={e => (e.currentTarget.style.color = "var(--accent)")}
                  onMouseLeave={e => (e.currentTarget.style.color = "var(--text-muted)")}
                >
                  <i className={`bi ${s.icon}`}></i>
                </a>
              ))}
            </div>
          </div>
          <div className="col-md-4 text-md-end">
            <p style={{ color: "var(--text-muted)", fontSize: "0.75rem", letterSpacing: "0.06em" }}>
              © 2025 Jerisha Y · All rights reserved
            </p>
          </div>
        </div>

        <div style={{ borderTop: "1px solid var(--border)", marginTop: "2rem", paddingTop: "1.5rem" }}>
          <div className="d-flex flex-wrap justify-content-center gap-3">
            {["/", "/about", "/skills", "/projects", "/certifications", "/contact"].map((p) => (
              <Link key={p} to={p} style={{
                color: "var(--text-muted)", fontSize: "0.72rem",
                letterSpacing: "0.1em", textTransform: "uppercase",
                textDecoration: "none", transition: "color 0.2s",
              }}
                onMouseEnter={e => (e.currentTarget.style.color = "var(--accent)")}
                onMouseLeave={e => (e.currentTarget.style.color = "var(--text-muted)")}
              >
                {p === "/" ? "Home" : p.slice(1).charAt(0).toUpperCase() + p.slice(2)}
              </Link>
            ))}
          </div>
        </div>
      </div>
    </footer>
  );
}
